\usetikzlibrary{angles,quotes}

\begin{document}
\begin{tikzpicture}[scale=2]
    % Define coordinates for a 3:4:5 right triangle
    \coordinate (A) at (0,0);
    \coordinate (B) at (3,0);
    \coordinate (C) at (3,4);

    % Draw the triangle
    \draw[thick] (A) -- (B) node[midway, below] {$1$};
    \draw[thick] (B) -- (C) node[midway, right] {$\beta$};
    \draw[thick] (C) -- (A) node[midway, above left] {$\gamma$};

    % Mark the right angle
    \draw ($(B)+(0.3,0)$) -- ($(B)+(0.3,0.3)$) -- ($(B)+(0,0.3)$);

    % Mark alpha angle
    \pic [draw, angle radius=0.5cm, "$\alpha$"] {angle=B--A--C};
\end{tikzpicture}
\end{document}

